import type { GameState, Player } from '../types';

type StateChangeListener = (state: GameState, changedKeys: string[]) => void;

interface StateSubscription {
    id: number;
    keys: string[];
    listener: StateChangeListener;
}

export class StateManager {
    private engine: unknown;
    private state: GameState;
    private subscriptions: StateSubscription[] = [];
    private subscriptionId: number = 0;
    private history: Array<{ state: GameState; timestamp: number }> = [];
    private maxHistorySize: number = 50;

    constructor(engine: unknown) {
        this.engine = engine;
        this.state = this.createInitialState();
    }

    private createInitialState(): GameState {
        return {
            player: null,
            currentLocation: 'tavern',
            currentView: 'main-menu',
            gameStarted: false,
            paused: false,
            gameTime: 0,
            weather: { type: 'clear', intensity: 1, duration: 0, effects: [] },
            time: { hour: 8, minute: 0, day: 1, month: 1, year: 1, period: 'morning' }
        };
    }

    getState(): GameState {
        return { ...this.state };
    }

    getStateValue<K extends keyof GameState>(key: K): GameState[K] {
        return this.state[key];
    }

    setState<K extends keyof GameState>(key: K, value: GameState[K]): void {
        this.state[key] = value;
        
        this.addToHistory();
        this.notifySubscribers([key]);
    }

    updateState(updates: Partial<GameState>): void {
        const changedKeys: string[] = [];
        
        for (const key in updates) {
            if (Object.prototype.hasOwnProperty.call(updates, key)) {
                (this.state as unknown as Record<string, unknown>)[key] = updates[key as keyof GameState];
                changedKeys.push(key);
            }
        }

        if (changedKeys.length > 0) {
            this.addToHistory();
            this.notifySubscribers(changedKeys);
        }
    }

    setPlayer(player: Player | null): void {
        this.state.player = player;
        this.addToHistory();
        this.notifySubscribers(['player']);
    }

    getPlayer(): Player | null {
        return this.state.player;
    }

    subscribe(keys: string[], listener: StateChangeListener): () => void {
        const id = ++this.subscriptionId;
        
        this.subscriptions.push({
            id,
            keys,
            listener
        });

        return () => {
            const index = this.subscriptions.findIndex(s => s.id === id);
            if (index !== -1) {
                this.subscriptions.splice(index, 1);
            }
        };
    }

    private notifySubscribers(changedKeys: string[]): void {
        for (const sub of this.subscriptions) {
            const hasMatchingKey = sub.keys.length === 0 || 
                sub.keys.some(k => changedKeys.includes(k));
            
            if (hasMatchingKey) {
                try {
                    sub.listener(this.getState(), changedKeys);
                } catch (e) {
                    console.error('状态监听器错误:', e);
                }
            }
        }
    }

    private addToHistory(): void {
        this.history.push({
            state: { ...this.state },
            timestamp: Date.now()
        });

        if (this.history.length > this.maxHistorySize) {
            this.history.shift();
        }
    }

    getHistory(): Array<{ state: GameState; timestamp: number }> {
        return [...this.history];
    }

    undo(): boolean {
        if (this.history.length < 2) {
            return false;
        }

        this.history.pop();
        const previous = this.history[this.history.length - 1];
        
        if (previous) {
            this.state = { ...previous.state };
            this.notifySubscribers(Object.keys(this.state));
            return true;
        }

        return false;
    }

    reset(): void {
        this.state = this.createInitialState();
        this.history = [];
        this.notifySubscribers(Object.keys(this.state));
    }

    exportState(): string {
        return JSON.stringify(this.state);
    }

    importState(json: string): boolean {
        try {
            const parsed = JSON.parse(json) as GameState;
            this.state = { ...this.createInitialState(), ...parsed };
            this.addToHistory();
            this.notifySubscribers(Object.keys(this.state));
            return true;
        } catch (e) {
            console.error('导入状态失败:', e);
            return false;
        }
    }
}

export default StateManager;
